    return random.choice(stocks)

def recommend_bond():
    bonds = ["BAC", "JPM", "JNJ", "MDT", "JFE"]
    random.shuffle(bonds)
    return random.choice(bonds)

def recommend_investment_product():
    investment_products = ["REITS", "CASH", "RENAIRES", "Bonds", "ETFs"]
