    return random.choice(investment_products)

def recommend_stock_recommendation():
    recommendation = {
        "Stocks": recommend_stock(),
        "Bonds": recommend_bond(),
        "Investment Products": recommend_investment_product()
    }
    return recommendation

# Example usage
print(recommend_stock_recommendation())
